/** End-to-end planning benchmark for the packed boundary and selected-plan materialization. */
@BenchmarkMode(Mode.AverageTime)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
@Warmup(iterations = 3, time = 1)
@Measurement(iterations = 5, time = 1)
@Fork(1)
public class PackedCascadesSearchBenchmark {

	@Benchmark
	public TupleExpr plan(PlannerState state) {
		return PackedCascadesPlanner.optimizeToTupleExpr(state.input);
	}

	@State(Scope.Thread)
	public static class PlannerState {

		@Param({ "4", "8" })
		public int factors;

		private TupleExpr template;
		private TupleExpr input;

		@Setup(Level.Trial)
		public void setupTrial() {
			SimpleValueFactory values = SimpleValueFactory.getInstance();
			TupleExpr root = pattern(values, 0);
			for (int ordinal = 1; ordinal < factors; ordinal++) {
				root = new Join(root, pattern(values, ordinal));
			}
			template = root;
		}

		@Setup(Level.Invocation)
		public void setupInvocation() {
			input = template.clone();
		}

		private static StatementPattern pattern(SimpleValueFactory values, int ordinal) {
			StatementPattern pattern = new StatementPattern(Var.of("chain" + ordinal),
					Var.of("predicate" + ordinal, values.createIRI("urn:predicate:" + ordinal)),
					Var.of("chain" + (ordinal + 1)));
			pattern.setResultSizeEstimate(10.0d * (ordinal + 1));
			return pattern;
		}
	}
}
